<section class="auth-shell shell"><div class="auth-card card"><div class="auth-heading"><img src="<?= $assetUrl('images/onion-mark.svg') ?>" alt=""><p class="eyebrow">Choose a new secret</p><h1 class="heading-auth">Create a new password</h1><p class="muted">A successful reset signs out other sessions and invalidates this link.</p></div><form class="form-stack" method="post" action="<?= $url('auth.password.update', [], '/reset-password') ?>"><?= function_exists('csrf_field')?csrf_field():'' ?><input type="hidden" name="token" value="<?= $esc((string)($data['token']??'')) ?>"><label class="field"><span>Email</span><input type="email" name="email" value="<?= $esc((string)($data['email']??'')) ?>" autocomplete="email" required></label><label class="field"><span>New password</span><input type="password" name="password" autocomplete="new-password" minlength="12" required><small>At least 12 characters; use a unique passphrase.</small></label><label class="field"><span>Confirm new password</span><input type="password" name="password_confirmation" autocomplete="new-password" minlength="12" required></label><button class="button button-gold button-wide">Reset password</button></form></div></section>
